1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	};
11	
12	const quoteItems = (items: Item[]): number => {
13	  if (items.length === 0) return PROCESSING_FEE;
14	  const item = items[0];
15	  const base = BASE_PREMIUMS[item.type];
16	  const firstInsurance = base * 0.1;
17	  return Math.ceil(base + firstInsurance + PROCESSING_FEE);
18	};
19	
20	export const runScenario = (input: Scenario): { results: { premium: number }[] } => {
21	  const results = input.steps.map((step) => ({ premium: quoteItems(step.items) }));
22	  return { results };
23	};
